// Função para procurar "dataset" e "page"
function findDatasetAndPage(jsonObj) {
    let result = {
        dataset: [],
        page: []
    };

    function searchInObject(obj) {
        if (obj && typeof obj === 'object') {
            // Coleta "dataset" e fallback para "fb_pixel"
            if (obj['dataset']) {
                result.dataset.push(...obj['dataset']);
            } else if (obj['fb_pixel']) {
                result.dataset.push(...obj['fb_pixel']);
            }

            // Coleta "page" apenas
            if (obj['page']) {
                result.page.push(...obj['page']);
            }

            // Percorre os sub-objetos e arrays recursivamente
            for (let key in obj) {
                if (obj.hasOwnProperty(key) && typeof obj[key] === 'object') {
                    searchInObject(obj[key]);
                }
            }
        }
    }

    searchInObject(jsonObj);
    return result;
}

// A entrada do n8n geralmente vem em um formato específico. Pegue os dados de entrada.
const inputData = $input.all();

let finalResult = [];

inputData.forEach(item => {
    // Use a função para procurar os valores de "dataset" e "page"
    const datasetsAndPages = findDatasetAndPage(item.json);

    // Adiciona os resultados encontrados apenas se houver pelo menos um dataset ou page
    if (datasetsAndPages.dataset.length > 0 || datasetsAndPages.page.length > 0) {
        finalResult.push({ json: datasetsAndPages });
    }
});

// Retorna os dados no formato esperado pelo n8n
return finalResult;

